SELECT total_ev, winner, margin, turnout
FROM election_results
WHERE state_id = 1 AND year_id = 1;

SELECT COUNT(*) AS total_voter_demographics_records
FROM voter_demographics
WHERE year_id = (SELECT year_id FROM election_years WHERE year = 1948);

SELECT total_ev
FROM election_results
WHERE year_id = 1;

SELECT SUM(total_ev) AS total_electoral_votes
FROM election_results
WHERE year_id = 1 AND state_id = 0;

SELECT headline, source
FROM election_news
WHERE date = '1948-11-04';

SELECT state_id, year_id, SUM(d_votes) AS total_d_votes, winner
FROM election_results
GROUP BY state_id, year_id;

SELECT COUNT(*) AS demographic_count
FROM voter_demographics
WHERE state_id = 1 AND age_bracket = '26-35';

SELECT SUM(total_ev) AS total_electoral_votes
FROM election_results
WHERE year_id = 1;

SELECT COUNT(*) AS total_mentions
FROM candidate_news_mentions
WHERE candidate_id = 0;

SELECT total_ev AS total_electoral_votes
FROM election_results
WHERE state_id = 1;

SELECT MAX(total_ev) AS max_electoral_votes
FROM election_results
WHERE year_id = 1;

SELECT COUNT(DISTINCT age_bracket) AS unique_age_brackets
FROM voter_demographics
WHERE state_id = 1 AND year_id = 0;
